module RefModule (  
    input [15:0] data_in,  
    input RE,  
    input WE,  
    input CLK,  
    output reg [15:0] data_out  
);  
    reg [15:0] obf_memory;  

    always @(posedge CLK) begin  
        if (WE)  
            obf_memory <= data_in;  
        if (RE)  
            data_out <= obf_memory;  
    end  
endmodule
